// Réception des événements Slack (réponses utilisateur)
export default async function handler(req, res) {
  const { type, event, challenge } = req.body;
  if (type === "url_verification") return res.json({ challenge });
  if (type === "event_callback" && event?.type === "message" && !event.bot_id) {
    // Forward to PHDDEC frontend (or store in DB / queue)
    await fetch(process.env.PHDDEC_REPLY_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ user: event.user, text: event.text, ts: event.ts }),
    });
  }
  res.status(200).end();
}

